files.css:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  line-height: 1.6;
  color: #333;
}

header {
  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.1);
}

nav {
  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.1);
}

main {
  min-height: 60vh;
}

section {
  margin-bottom: 2rem;
}

h2 {
  font-size: 2rem;
  margin-bottom: 1rem;
}

button {
  transition: all 0.3s ease;
}

button:hover {
  opacity: 0.9;
  transform: translateY(-2px);
}

